import { describe, expect, it } from 'vitest';
import {
  lorentzGamma,
  lorentzBoostEvent,
  lorentzBoostEvents,
  simultaneitySlice,
} from './simultaneity';
import { LIGHT_PICOLORENZO_LY } from './math';
import type { SpacetimeEvent } from './causal-topology';

// ─── Helpers ────────────────────────────────────────────────────────

function makeEvent(
  id: string,
  x: number,
  y: number,
  z: number,
  pLo: number
): SpacetimeEvent {
  return { id, label: id, x, y, z, pLo };
}

/** Spacetime interval ds^2 = -dt^2 + dx^2 + dy^2 + dz^2 in natural units. */
function dsSquared(a: SpacetimeEvent, b: SpacetimeEvent): number {
  const dxLpLo = (b.x - a.x) / LIGHT_PICOLORENZO_LY;
  const dyLpLo = (b.y - a.y) / LIGHT_PICOLORENZO_LY;
  const dzLpLo = (b.z - a.z) / LIGHT_PICOLORENZO_LY;
  const dt = b.pLo - a.pLo;
  return -(dt * dt) + dxLpLo * dxLpLo + dyLpLo * dyLpLo + dzLpLo * dzLpLo;
}

// ─── lorentzGamma ───────────────────────────────────────────────────

describe('lorentzGamma', () => {
  it('gamma(0) = 1 (rest frame)', () => {
    expect(lorentzGamma(0)).toBe(1);
  });

  it('gamma(0.5) ≈ 1.1547', () => {
    expect(lorentzGamma(0.5)).toBeCloseTo(1.1547, 3);
  });

  it('gamma(0.866) ≈ 2.0', () => {
    expect(lorentzGamma(0.866)).toBeCloseTo(2.0, 1);
  });

  it('gamma(0.99) ≈ 7.089', () => {
    expect(lorentzGamma(0.99)).toBeCloseTo(7.089, 2);
  });

  it('throws for beta = 1 (speed of light)', () => {
    expect(() => lorentzGamma(1)).toThrow(RangeError);
  });

  it('throws for beta = -1', () => {
    expect(() => lorentzGamma(-1)).toThrow(RangeError);
  });

  it('throws for superluminal beta > 1', () => {
    expect(() => lorentzGamma(1.5)).toThrow(RangeError);
  });

  it('handles negative beta symmetrically', () => {
    expect(lorentzGamma(-0.5)).toBeCloseTo(lorentzGamma(0.5), 10);
  });
});

// ─── lorentzBoostEvent ──────────────────────────────────────────────

describe('lorentzBoostEvent', () => {
  it('event at origin is unchanged by any boost', () => {
    const origin = makeEvent('origin', 0, 0, 0, 0);
    const boosted = lorentzBoostEvent(origin, 0.5);
    expect(boosted.x).toBeCloseTo(0, 10);
    expect(boosted.pLo).toBeCloseTo(0, 10);
    expect(boosted.y).toBe(0);
    expect(boosted.z).toBe(0);
  });

  it('event at (4.24 ly, 0, 0) gets time-shifted when boosted', () => {
    const proxima = makeEvent('proxima', 4.24, 0, 0, 1000);
    const boosted = lorentzBoostEvent(proxima, 0.5);

    // The boosted time should differ from the original
    expect(boosted.pLo).not.toBeCloseTo(proxima.pLo, 0);
    // Original values are preserved
    expect(boosted.originalPLo).toBe(1000);
    expect(boosted.originalX).toBe(4.24);
    expect(boosted.gamma).toBeCloseTo(lorentzGamma(0.5), 10);
    expect(boosted.beta).toBe(0.5);
  });

  it('y and z coordinates are unchanged', () => {
    const event = makeEvent('off-axis', 1.0, 2.5, -3.7, 500);
    const boosted = lorentzBoostEvent(event, 0.8);
    expect(boosted.y).toBe(2.5);
    expect(boosted.z).toBe(-3.7);
  });
});

// ─── beta = 0 identity ─────────────────────────────────────────────

describe('beta = 0 identity', () => {
  it('returns original events unchanged when beta = 0', () => {
    const events = [
      makeEvent('a', 1.0, 0, 0, 100),
      makeEvent('b', 5.0, 0, 0, 200),
      makeEvent('c', 0, 3.0, 0, 300),
    ];
    const boosted = lorentzBoostEvents(events, 0);

    for (let i = 0; i < events.length; i++) {
      expect(boosted[i].x).toBeCloseTo(events[i].x, 10);
      expect(boosted[i].y).toBe(events[i].y);
      expect(boosted[i].z).toBe(events[i].z);
      expect(boosted[i].pLo).toBeCloseTo(events[i].pLo, 10);
      expect(boosted[i].gamma).toBe(1);
      expect(boosted[i].beta).toBe(0);
    }
  });
});

// ─── Boost invertibility ────────────────────────────────────────────

describe('boost invertibility', () => {
  it('boost at beta then -beta returns original coordinates', () => {
    const event = makeEvent('star', 4.24, 1.5, -0.3, 750);
    const beta = 0.6;

    const boosted = lorentzBoostEvent(event, beta);
    const recovered = lorentzBoostEvent(boosted, -beta);

    expect(recovered.x).toBeCloseTo(event.x, 8);
    expect(recovered.y).toBe(event.y);
    expect(recovered.z).toBe(event.z);
    expect(recovered.pLo).toBeCloseTo(event.pLo, 8);
  });

  it('invertibility holds for high-gamma boosts', () => {
    const event = makeEvent('fast', 10.0, 0, 0, 2000);
    const beta = 0.99;

    const boosted = lorentzBoostEvent(event, beta);
    const recovered = lorentzBoostEvent(boosted, -beta);

    expect(recovered.x).toBeCloseTo(event.x, 6);
    expect(recovered.pLo).toBeCloseTo(event.pLo, 6);
  });
});

// ─── Simultaneity breaks ────────────────────────────────────────────

describe('simultaneity breaks', () => {
  it('two simultaneous events at different x break simultaneity when boosted', () => {
    const t = 1000;
    const events = [
      makeEvent('left', 0, 0, 0, t),
      makeEvent('right', 4.24, 0, 0, t),
    ];

    const slice = simultaneitySlice(events, 0.5);

    // They were simultaneous (same pLo) but after boost they should not be
    expect(slice.simultaneityBreaks.length).toBe(1);
    expect(slice.simultaneityBreaks[0].eventA).toBe('left');
    expect(slice.simultaneityBreaks[0].eventB).toBe('right');
    expect(slice.simultaneityBreaks[0].originalDtPLo).toBe(0);
    expect(slice.simultaneityBreaks[0].boostedDtPLo).not.toBeCloseTo(0, 5);
  });

  it('co-located simultaneous events remain simultaneous', () => {
    const t = 500;
    const events = [
      makeEvent('here1', 0, 0, 0, t),
      makeEvent('here2', 0, 0, 0, t),
    ];

    const slice = simultaneitySlice(events, 0.8);

    // Same position means the boost shifts time identically -- no break
    expect(slice.simultaneityBreaks.length).toBe(0);
  });

  it('slice has correct metadata', () => {
    const events = [makeEvent('a', 0, 0, 0, 100)];
    const slice = simultaneitySlice(events, 0.3);

    expect(slice.source).toBe('GnosisSimultaneitySlice');
    expect(slice.beta).toBe(0.3);
    expect(slice.gamma).toBeCloseTo(lorentzGamma(0.3), 10);
    expect(slice.boostedEvents.length).toBe(1);
  });

  it('beta = 0 produces no simultaneity breaks', () => {
    const events = [
      makeEvent('a', 0, 0, 0, 100),
      makeEvent('b', 10.0, 0, 0, 100),
      makeEvent('c', 5.0, 0, 0, 200),
    ];

    const slice = simultaneitySlice(events, 0);
    expect(slice.simultaneityBreaks.length).toBe(0);
  });
});

// ─── Spacetime interval invariance ──────────────────────────────────

describe('interval invariance (ds^2 preserved under boost)', () => {
  it('ds^2 is the same before and after a boost for a spacelike pair', () => {
    const a = makeEvent('a', 0, 0, 0, 100);
    const b = makeEvent('b', 4.24, 0, 0, 100);
    const beta = 0.6;

    const originalDs2 = dsSquared(a, b);

    const aBoosted = lorentzBoostEvent(a, beta);
    const bBoosted = lorentzBoostEvent(b, beta);
    const boostedDs2 = dsSquared(aBoosted, bBoosted);

    expect(boostedDs2).toBeCloseTo(originalDs2, 6);
  });

  it('ds^2 is invariant for a timelike pair', () => {
    const a = makeEvent('a', 0, 0, 0, 0);
    const b = makeEvent('b', 0.001, 0, 0, 1000);
    const beta = 0.8;

    const originalDs2 = dsSquared(a, b);
    const aBoosted = lorentzBoostEvent(a, beta);
    const bBoosted = lorentzBoostEvent(b, beta);
    const boostedDs2 = dsSquared(aBoosted, bBoosted);

    expect(boostedDs2).toBeCloseTo(originalDs2, 4);
  });

  it('ds^2 is invariant for a pair with off-axis coordinates', () => {
    const a = makeEvent('a', 1.0, 2.0, 3.0, 500);
    const b = makeEvent('b', 5.0, 2.0, 3.0, 800);
    const beta = 0.45;

    const originalDs2 = dsSquared(a, b);
    const aBoosted = lorentzBoostEvent(a, beta);
    const bBoosted = lorentzBoostEvent(b, beta);
    const boostedDs2 = dsSquared(aBoosted, bBoosted);

    // y and z unchanged, so the transverse part cancels -- only x and t transform
    expect(boostedDs2).toBeCloseTo(originalDs2, 6);
  });

  it('ds^2 invariance holds at high gamma', () => {
    const a = makeEvent('a', 0, 0, 0, 0);
    const b = makeEvent('b', 2.0, 1.0, 0.5, 300);
    const beta = 0.995;

    const originalDs2 = dsSquared(a, b);
    const aBoosted = lorentzBoostEvent(a, beta);
    const bBoosted = lorentzBoostEvent(b, beta);
    const boostedDs2 = dsSquared(aBoosted, bBoosted);

    expect(boostedDs2).toBeCloseTo(originalDs2, 3);
  });
});
